// Test the landing squash values are reasonable
function easeOutElastic\(t\) {
  if \(t === 0 || t === 1\) return t;
  return Math.pow\(2, -10 * t\) * Math.sin\(\(t * 10 - 0.75\) * \(2 * Math.PI / 3\)\) + 1;
}
// Simulate landSquash from 12 down to 0
for \(let f = 12; f >= 0; f--\) {
  const raw = f / 12;
  const t = easeOutElastic\(1 - raw\);
  const sx = 1 + \(1 - t\) * 0.25;
  const sy = 1 - \(1 - t\) * 0.25;
  console.log\('frame', 12-f, ': scaleX=' + sx.toFixed\(3\) + ' scaleY=' + sy.toFixed\(3\)\);
}
")
